import java.util.*;

public class HashMapInternals {

    // Custom key — must implement hashCode + equals correctly
    static class Point {
        final int x, y;
        Point(int x, int y) { this.x = x; this.y = y; }

        @Override public int hashCode() {
            return Objects.hash(x, y); // uses prime multiplication
        }
        @Override public boolean equals(Object o) {
            if (!(o instanceof Point p)) return false;
            return x == p.x && y == p.y;
        }
        @Override public String toString() { return "(" + x + "," + y + ")"; }
    }

    public static void main(String[] args) {
        // ── Basic ops ────────────────────────────────────────
        Map<Point, String> map = new HashMap<>();
        map.put(new Point(1,2), "A");
        map.put(new Point(3,4), "B");
        map.put(new Point(1,2), "C"); // replaces A (equal key)
        System.out.println(map.size()); // 2
        System.out.println(map.get(new Point(1,2))); // C

        // ── If hashCode broken (all return 42) → O(n) ────────
        // Every entry lands in bucket 42 → full linked list scan

        // ── Demonstrate resize ────────────────────────────────
        Map<Integer,Integer> growing = new HashMap<>();
        for (int i = 0; i < 13; i++) growing.put(i, i); // 16*0.75=12 → resize at 13
        System.out.println("After 13 entries: size=" + growing.size());
        // Internal capacity is now 32

        // ── computeIfAbsent — cleaner than containsKey+put ────
        Map<String, List<Integer>> groups = new HashMap<>();
        groups.computeIfAbsent("evens", k -> new ArrayList<>()).add(2);
        groups.computeIfAbsent("evens", k -> new ArrayList<>()).add(4); // reuses existing
        System.out.println(groups); // {evens=[2, 4]}

        // ── merge — great for counting ─────────────────────────
        String text = "a b a c b a";
        Map<String,Integer> freq = new HashMap<>();
        for (String w : text.split(" "))
            freq.merge(w, 1, Integer::sum);
        System.out.println(freq); // {a=3, b=2, c=1}
    }
}

import java.util.*;
import java.util.concurrent.*;

public class OrderingAndIterators {

    // Comparable: natural order (by salary)
    static class Employee implements Comparable<Employee> {
        String name; int salary;
        Employee(String name, int salary) { this.name = name; this.salary = salary; }
        @Override public int compareTo(Employee o) { return Integer.compare(this.salary, o.salary); }
        @Override public String toString() { return name + "(" + salary + ")"; }
    }

    public static void main(String[] args) {
        List<Employee> emps = new ArrayList<>(List.of(
            new Employee("Alice", 80000),
            new Employee("Bob",   50000),
            new Employee("Carol", 95000)
        ));

        // Natural order (Comparable)
        Collections.sort(emps);
        System.out.println("By salary: " + emps);

        // External Comparator (by name)
        emps.sort(Comparator.comparing(e -> e.name));
        System.out.println("By name: " + emps);

        // Chained comparators
        emps.sort(Comparator.comparingInt((Employee e) -> e.salary).reversed()
                            .thenComparing(e -> e.name));
        System.out.println("Desc salary, then name: " + emps);

        // ── Fail-fast: ConcurrentModificationException ────────
        List<String> list = new ArrayList<>(List.of("a","b","c"));
        try {
            for (String s : list) {
                if (s.equals("b")) list.remove(s); // structural mod → CME
            }
        } catch (ConcurrentModificationException e) {
            System.out.println("CME caught — fail-fast iterator");
        }

        // FIX: use removeIf
        list.removeIf(s -> s.equals("b"));
        System.out.println("After removeIf: " + list); // [a, c]

        // ── Fail-safe: CopyOnWriteArrayList ──────────────────
        CopyOnWriteArrayList<String> cowList = new CopyOnWriteArrayList<>(List.of("x","y","z"));
        for (String s : cowList) {
            if (s.equals("y")) cowList.remove(s); // safe — iterates snapshot
        }
        System.out.println("COW after remove: " + cowList); // [x, z]
    }
}

