import java.util.*;

public class Q3 {
    static class Student { String name; double gpa;
        Student(String n, double g) { name=n; gpa=g; }
        public String toString() { return name+"("+gpa+")"; }
    }
    public static List<Student> sortStudents(List<Student> students) {
        students.sort(Comparator.comparingDouble((Student s) -> s.gpa)
                                .reversed()
                                .thenComparing(s -> s.name));
        return students;
    }
    public static void main(String[] args) {
        List<Student> s = new ArrayList<>(List.of(
            new Student("Bob",3.8), new Student("Alice",3.9),
            new Student("Carol",3.8), new Student("Dave",4.0)));
        System.out.println(sortStudents(s));
    }
}
